int test_calculation_reset(int a, int b, int c) {
    using namespace reaction;

    // Create reactive variables
    auto varA = var(a);
    auto varB = var(b);
    auto varC = var(c);

    // Create initial calculation: result = a + b
    auto calculation = calc([](int x, int y) {
